#include <bits/stdc++.h>//hd
//#include<gen.h>
using namespace std;
#define ll long long
const int N=2e5+5;
int n,v[N],ceng[N];
int swp(int a,int b);
bool flag;int V;
int dfs(int i){
//	assert(v[i]==V);
//	if(flag)
//	{
//		printf("dfs %d :: ",i);
//		rep(1,n,i)printf("%d ",v[i]);puts("");
//		printf("cnm :: %d\n",V);
//	}
    if(i*2>n)return i;
    int a=v[i],b=v[i*2],c=v[i*2+1];
    if(i*2+1>n){
        if(a<b)return i;
        else return i*2;//不影响 
    }
    else{
        if(a<b&&a<c)return i;
        if(b<a&&a<c)return swp(i,i*2);
        else if(b<c&&c<a)return swp(i,i*2);
        else if(c<b&&c<a){
            if(b>a)swap(v[i],v[i*2]);
            int p1=dfs(i*2);
            swap(v[i],v[i*2]);
            swap(v[i],v[i*2+1]);
            int p2=dfs(i*2+1);
            swap(v[i],v[i*2+1]);
            swap(v[i],v[i*2]);
            if(b>a)
			{
				int x=0;
				swap(v[i],v[i*2]);
				if(p1<p2)
				{
					swap(v[i],v[i*2+1]);
					swap(v[i*2],v[i*2+1]);
					x=dfs(i*2);
					swap(v[i*2],v[i*2+1]);
					swap(v[i],v[i*2+1]); 
				}
				else
				{
					swap(v[i],v[i*2+1]);
					x=dfs(i*2+1);
					swap(v[i],v[i*2+1]);
				}
				return x;
			}
			int x=0;
			if(p1<p2)
			{
				swap(v[i],v[i*2+1]);
				x=dfs(i*2+1);
				swap(v[i],v[i*2+1]);
			}
			else
			{
				swap(v[i],v[i*2+1]);
				swap(v[i*2],v[i*2+1]);
				x=dfs(i*2);
				swap(v[i*2],v[i*2+1]);
				swap(v[i],v[i*2+1]); 
			}

            return x;
            // if(p1>p2)swap(v[i],v[i*2]);
            // swap(v[i],v[i*2+1]);
        }
    }
    assert(false);
}
int swp(int a,int b){
    swap(v[a],v[b]);
    int p=dfs(b);
    swap(v[a],v[b]);
    return p;
}
int main(){
    //freopen("ex_swap5.in","r",stdin);
    //freopen("ex_swap.out","w",stdout);
//    FIN("data.in");
//    FOUT("mine.out");
    cin>>n;
    int k=1<<(__lg(n+1))-1;
    for(int i=1;i<=n;i++){
        cin>>v[i];
        ceng[i]=__lg(i);
    }
    for(int i=1;i<=n/2;i++){
        int a=v[i],b=v[i*2],c=v[i*2+1];
        if(i*2+1>n){
            if(a<b)continue;
            else swap(v[i],v[i*2]);
        }
        else{
            if(a<b&&a<c)continue;
            if(b<a&&a<c)swap(v[i],v[i*2]);
            else if(b<c&&c<a)swap(v[i],v[i*2]);
            else if(c<b&&c<a){ 
                if(b>a)swap(v[i],v[i*2]);
                if(i==2)flag=true;
                V=v[i*2];
                int p1=dfs(i*2);
                flag=false;
                swap(v[i],v[i*2]);
                swap(v[i],v[i*2+1]);
                int p2=dfs(i*2+1);
                swap(v[i],v[i*2+1]);
                swap(v[i],v[i*2]);
//                if(i==2)printf("cnm %d %d\n",p1,p2);
                if(p1>p2)swap(v[i],v[i*2]);
                swap(v[i],v[i*2+1]);
            }
        }
    }
    for(int i=1;i<=n;i++){
        cout<<v[i]<<' ';
    }
    return 0;
}
